    42|export const IVX_SENIOR_DEV_WORKER_MARKER = 'ivx-senior-developer-worker-2026-06-16';
    43|
    44|/** Repo-relative keys so the durable store derives stable doc keys. */
    45|const QUEUE_FILE = 'logs/audit/senior-developer-worker/queue.json';
    46|const LEDGER_FILE = 'logs/audit/senior-developer-worker/proof-ledger.json';
    47|
    48|const MAX_QUEUE_RETAINED = 200;
    49|const MAX_LEDGER_RETAINED = 200;
    50|
    51|export type IVXWorkerJobStatus = 'queued' | 'running' | 'completed' | 'failed' | 'blocked';
    52|
    53|/** Owner-approved task accepted by the worker. Never carries secret values. */
    54|export type IVXWorkerJobInput = {
