   127|
   128|function nowIso(): string {
   129|  return new Date().toISOString();
   130|}
   131|
   132|function emptyQueue(durable: boolean): QueueDoc {
   133|  return { marker: IVX_SENIOR_DEV_WORKER_MARKER, durable, updatedAt: nowIso(), jobs: [] };
