   139|
   140|/**
   141| * In-memory mirror so the queue/worker keep functioning even when Supabase is
   142| * not configured (local dev / tests) and to avoid a read-modify-write race
   143| * between the enqueue call and the async drain.
   144| */
   145|let memoryQueue: QueueDoc | null = null;
   146|let memoryLedger: LedgerDoc | null = null;
   147|let draining = false;
   148|
   149|async function loadQueue(): Promise<QueueDoc> {
