   152|    if (!memoryQueue) memoryQueue = emptyQueue(false);
   153|    return memoryQueue;
   154|  }
   155|  try {
   156|    const doc = await readDurableJson<QueueDoc>(QUEUE_FILE, emptyQueue(true));
   157|    return { ...doc, marker: IVX_SENIOR_DEV_WORKER_MARKER, durable: true };
   158|  } catch {
   159|    if (!memoryQueue) memoryQueue = emptyQueue(false);
