   230|export async function toolIncidentAnalyze(input: { limit?: number; minRepeat?: number }) {
   231|  const limit = Math.max(10, Math.min(500, Number(input.limit) || 100));
   232|  const minRepeat = Math.max(1, Number(input.minRepeat) || 1);
   233|  const incidents = listIncidents(limit);
   234|  const groups = new Map<string, { signature: string; count: number; sample: IVXIncident; severities: Set<string>; sources: Set<string>; lastAt: string }>();
   235|  for (const inc of incidents) {
   236|    const sig = hashSignature(inc.message, inc.fileLine);
   237|    const existing = groups.get(sig);
   238|    if (existing) {
   239|      existing.count += 1;
   240|      existing.severities.add(inc.severity);
   241|      existing.sources.add(inc.source);
   242|      if (inc.createdAt > existing.lastAt) existing.lastAt = inc.createdAt;
   243|    } else {
   244|      groups.set(sig, { signature: sig, count: 1, sample: inc, severities: new Set([inc.severity]), sources: new Set([inc.source]), lastAt: inc.createdAt });
   245|    }
   246|  }
   247|  const clusters = Array.from(groups.values())
   248|    .filter((g) => g.count >= minRepeat)
   249|    .sort((a, b) => b.count - a.count)
   250|    .map((g) => ({
   251|      signature: g.signature,
   252|      count: g.count,
   253|      severities: Array.from(g.severities),
   254|      sources: Array.from(g.sources),
   255|      lastAt: g.lastAt,
   256|      sampleId: g.sample.id,
   257|      sampleMessage: g.sample.message,
   258|      sampleFileLine: g.sample.fileLine,
   259|      sampleCheckpoint: g.sample.checkpoint,
   260|      sampleStatus: g.sample.status,
   261|    }));
   262|  const openCount = incidents.filter((i) => i.status === 'open' || i.status === 'awaiting_approval' || i.status === 'awaiting_production_approval').length;
   263|  return {
   264|    ok: true,
   265|    total: incidents.length,
   266|    openCount,
   267|    clusterCount: clusters.length,
   268|    topClusters: clusters.slice(0, 20),
   269|  };
   270|}
