   388|/**
   389| * Curated, runtime-safe backend test suites that SHIP in the production image
   390| * (`COPY backend ./backend`) and do NOT transitively pull the heavy AI runtime
   391| * (the optional `ai` package). With `bun` now present in the prod container
   392| * (Gap #1), these run as a GENUINE native `bun test` execution in-container —
   393| * not a degraded import-smoke. Pure/deterministic suites are chosen so a green
   394| * run is a real signal and a red run is a real failure.
   395| */
   396|const CONTAINER_NATIVE_TEST_SUITES: string[] = [
   397|  'backend/services/ivx-runtime-resolver.test.ts',
   398|  'backend/services/ivx-continuous-improvement.test.ts',
   399|  'backend/services/ivx-evidence-gate.test.ts',
