   405|/**
   406| * Native in-container test execution via the real `bun test` runner.
   407| *
   408| * Gap #1: once `bun` is shipped in the production image, the autonomous
   409| * lifecycle's step 6 runs a TRUE native test execution against the curated
   410| * backend suites that ship in the container — no degrade, no fabrication. Only
   411| * the suites that exist on disk are passed to the runner; a genuine test
   412| * failure fails honestly (`exitCode != 0`).
   413| */
   414|async function runNativeBunTest(requestedSuite: string) {
   415|  const present: string[] = [];
   416|  for (const rel of CONTAINER_NATIVE_TEST_SUITES) {
   417|    if (await fileExists(rel)) present.push(rel);
   418|  }
   419|  if (present.length === 0) {
   420|    // No shipped suites to run — degrade honestly rather than report a false pass.
   421|    return runImportSmokeValidation(requestedSuite);
   422|  }
   423|  const r = await runProcess('bun', ['test', ...present], 120_000);
   424|  return {
   425|    ok: r.code === 0 && !r.timedOut,
   426|    suite: requestedSuite,
   427|    native: true as const,
   428|    effectiveCheck: 'bun-test' as const,
   429|    exitCode: r.code,
   430|    timedOut: r.timedOut,
   431|    suitesRun: present.length,
   432|    stdoutTail: r.out.slice(-4000),
   433|    stderrTail: r.err.slice(-4000),
   434|    note: `Ran native \`bun test\` over ${present.length} shipped backend suite(s) in-container.`,
   435|  };
   436|}
