   510|    const id = typeof input.incidentId === 'string' ? input.incidentId.trim() : '';
   511|    if (!id) return { ok: false, error: 'incidentId is required for replay' };
   512|    const r = await replayIncidentAgainstStaging(id);
   513|    return { ok: r.ok, suite, result: r };
   514|  }
   515|  return { ok: false, error: `unknown suite '${suite}' (use typecheck|lint|smoke|replay)` };
   516|}
