   143|/**
   144| * Run the full self-upgrade lifecycle for ONE tool. If `name` is omitted, the
   145| * agent proposes the next safe tool itself. This is the end-to-end success-test
   146| * entry point: propose → build → test → activate → use → proof.
   147| */
   148|export async function runSelfUpgrade(
   149|  name?: string,
   150|  env: NodeJS.ProcessEnv = process.env,
   151|): Promise<SelfUpgradeProof> {
   152|  // 1. Propose.
   153|  let proposal: ToolProposal | null;
   154|  if (name) {
   155|    const def = getCatalogTool(name);
   156|    if (!def) {
   157|      return {
   158|        marker: IVX_TOOL_SELF_UPGRADE_MARKER,
   159|        ok: false,
   160|        proposal: null,
   161|        install: null,
   162|        usage: null,
   163|        registered: null,
   164|        finalLabel: TOOL_OUTPUT_LABEL.NOT_EXECUTED,
   165|        summary: `No approved-catalog tool named "${name}" — self-upgrade restricted to the approved source.`,
   166|      };
   167|    }
   168|    const scan = scanToolForSafety(def);
   169|    proposal = {
   170|      name: def.name,
   171|      purpose: def.purpose,
   172|      riskLevel: scan.riskLevel,
   173|      requiresApproval: scan.requiresApproval,
   174|      approvalCategories: scan.approvalCategories,
   175|      rationale: `Owner-requested build of approved tool "${def.name}".`,
   176|    };
   177|  } else {
   178|    proposal = await proposeNextTool();
   179|  }
   180|
   181|  if (!proposal) {
   182|    return {
   183|      marker: IVX_TOOL_SELF_UPGRADE_MARKER,
   184|      ok: true,
   185|      proposal: null,
   186|      install: null,
   187|      usage: null,
   188|      registered: null,
   189|      finalLabel: TOOL_OUTPUT_LABEL.NOT_EXECUTED,
