   105|async function ghFetch<T = unknown>(
   106|  path: string,
   107|  opts: { method?: string; body?: unknown } = {},
   108|): Promise<{ ok: boolean; status: number; data: T | null; error: string | null }> {
   109|  const token = getToken();
   110|  if (!token) return { ok: false, status: 0, data: null, error: 'GITHUB_TOKEN not configured' };
   111|
   112|  const url = path.startsWith('http') ? path : `${GITHUB_API}${path}`;
   113|  const headers: Record<string, string> = {
   114|    Authorization: `Bearer ${token}`,
   115|    Accept: 'application/vnd.github+json',
   116|    'X-GitHub-Api-Version': '2022-11-28',
   117|  };
   118|  if (opts.body) headers['Content-Type'] = 'application/json';
   119|
   120|  try {
   121|    const res = await fetch(url, {
   122|      method: opts.method ?? 'GET',
   123|      headers,
   124|      body: opts.body ? JSON.stringify(opts.body) : undefined,
   125|    });
   126|    const text = await res.text();
   127|    const data = text ? (JSON.parse(text) as T) : null;
   128|    if (!res.ok) {
   129|      return { ok: false, status: res.status, data, error: `GitHub API ${res.status}: ${text.slice(0, 500)}` };
   130|    }
   131|    return { ok: true, status: res.status, data, error: null };
