    'supabase.audit',
    'production.health',
    'production.version',
    'commit.match',
  ];

  const results: ToolResult[] = [];
  for (const name of quickTools) {
    results.push(await executeTool(name));
  }
  return results;
}

export default { executeTool, executeAllTools, runIndependenceCheck, TOOL_CATALOG, EXTENDED_TOOLS, TOOL_ENGINE_MARKER };
