  | 'ai_developer_tools'
  | 'deployment_automation'
  | 'github_automation'
  | 'render_vercel_aws_automation'
  | 'supabase_automation'
  | 'ai_coding_agents'
  | 'security_tools'
  | 'qa_testing_tools'
  | 'real_estate_ai'
  | 'investor_discovery';

export type ScanResult = {
  category: ScanCategory;
  label: string;
  tools: Array<{
    name: string;
    url: string | null;
    description: string;
    relevance: 'high' | 'medium' | 'low';
  }>;
  searched: boolean;
  searchedAt: string | null;
  error: string | null;
};

export type TechnologyScanReport = {
  marker: string;
  generatedAt: string;
  scanId: string;
  categories: ScanResult[];
  summary: {
    totalTools: number;
    categoriesSearched: number;
    totalCategories: number;
    highRelevance: number;
  };
